import random, json

def stratified_sample(cases: list[dict], n: int) -> list[dict]:
    """Sample n cases preserving stratum proportions, over-sampling failures."""
    by_stratum: dict[str, list] = {}
    for c in cases:
        key = (c.get("length_bucket", "medium"), c.get("topic", "general"))
        by_stratum.setdefault(key, []).append(c)

    # Give failures 3x weight in sampling
    weighted = []
    for stratum, group in by_stratum.items():
        failures = [c for c in group if c.get("was_failure")]
        normal   = [c for c in group if not c.get("was_failure")]
        weighted.extend(failures * 3)
        weighted.extend(normal)

    return random.sample(weighted, min(n, len(weighted)))

import hashlib, json

def suite_hash(cases: list[dict]) -> str:
    """Stable hash of a test suite for reproducibility tracking."""
    sorted_ids = sorted(c["id"] for c in cases)
    return hashlib.sha256(json.dumps(sorted_ids).encode()).hexdigest()[:16]

def run_eval(cases: list[dict], model: str, grader) -> dict:
    h = suite_hash(cases)
    results = [grader(c, model) for c in cases]
    score = sum(r["correct"] for r in results) / len(results)
    return {"suite_hash": h, "model": model, "score": score, "n": len(cases)}

def tag_case(case: StreamCase, prev_case: StreamCase | None) -> list[str]:
    tags = []
    if case.latency_ms > 5000:
        tags.append("slow-response")
    if len(case.output_text.split()) < 20:
        tags.append("short-output")
    if prev_case and prev_case.session_id == case.session_id:
        # Consecutive message in session — potential correction
        if any(w in case.input_text.lower() for w in ["no,", "actually", "i meant", "wrong"]):
            tags.append("user-correction")
    return tags

from anthropic import Anthropic

client = Anthropic()

def rubric_grade(input_text: str, model_output: str, rubric: dict) -> dict:
    """Grade against a rubric rather than a single gold output."""
    criteria_text = "\n".join(f"- {k}: {v}" for k, v in rubric.items())
    prompt = f"""You are grading a model response.

Task input:
{input_text}

Model output:
{model_output}

Rubric criteria (score each 1-5):
{criteria_text}

Return JSON: {{"scores": {{"criterion": score, ...}}, "overall": float, "rationale": "..."}}"""

    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=512,
        messages=[{"role": "user", "content": prompt}]
    )
    import json
    return json.loads(response.content[0].text)
